package ports

import (
	"context"
	"errors"
	"net/http"
	"strconv"

	"github.com/labstack/echo/v4"

	"github.com/evgeniy-klemin/todo/internal/item/app"
)

// errorStatusMap maps app error kinds to HTTP status codes.
var errorStatusMap = map[error]int{
	app.ErrNotFound:   http.StatusNotFound,
	app.ErrValidation: http.StatusUnprocessableEntity,
}

// ItemService defines the port that the HTTP handler requires from the application layer.
type ItemService interface {
	Create(ctx context.Context, name string, position *int) (*app.Item, error)
	GetItemByID(ctx context.Context, id string) (*app.Item, error)
	List(ctx context.Context, query app.ListQuery) (app.ListResult, error)
	Update(ctx context.Context, reqItem *app.Item) (*app.Item, error)
}

func httpError(ctx echo.Context, err error) error {
	var appErr *app.AppError
	if errors.As(err, &appErr) {
		if status, ok := errorStatusMap[appErr.Kind]; ok {
			return ctx.JSON(status, map[string]string{"error": appErr.UserMessage})
		}
	}
	return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "internal server error"})
}

type HttpServer struct {
	itemService ItemService
}

func NewHttpServer(itemService ItemService) *HttpServer {
	return &HttpServer{
		itemService: itemService,
	}
}

// (GET /items)
func (h *HttpServer) GetItems(ctx echo.Context, params GetItemsParams) error {
	query, err := buildListQuery(params)
	if err != nil {
		return httpError(ctx, err)
	}

	result, err := h.itemService.List(ctx.Request().Context(), query)
	if err != nil {
		return httpError(ctx, err)
	}

	paginator := NewPaginator(query.Page, query.PerPage, result.TotalCount)
	ctx.Response().Header().Set("X-Page", strconv.Itoa(query.Page))
	ctx.Response().Header().Set("X-Per-Page", strconv.Itoa(query.PerPage))
	ctx.Response().Header().Set("X-Total-Count", strconv.Itoa(result.TotalCount))
	ctx.Response().Header().Set("Link", links(ctx.Request(), paginator))

	return ctx.JSON(http.StatusOK, appItemsToRespItems(result.Items))
}

func buildListQuery(params GetItemsParams) (app.ListQuery, error) {
	fields, err := getAppFieldsFromGetParam(params.Fields)
	if err != nil {
		return app.ListQuery{}, err
	}
	sortFields, err := getSortFieldsFromGetParam(params.Sort)
	if err != nil {
		return app.ListQuery{}, err
	}
	page := 1
	if params.Page != nil {
		page = int(*params.Page)
	}
	perPage := 20
	if params.PerPage != nil {
		perPage = int(*params.PerPage)
	}
	return app.ListQuery{
		Done:       params.Done,
		Search:     params.Q,
		Fields:     fields,
		Page:       page,
		PerPage:    perPage,
		SortFields: sortFields,
	}, nil
}

// Create New User
// (POST /items)
func (h *HttpServer) PostItems(ctx echo.Context) error {
	var itemPost ItemPost
	if err := ctx.Bind(&itemPost); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "некорректные параметры"})
	}
	var position *int
	if itemPost.Position != nil {
		positionVal := int(*itemPost.Position)
		position = &positionVal
	}
	item, err := h.itemService.Create(ctx.Request().Context(), itemPost.Name, position)
	if err != nil {
		return httpError(ctx, err)
	}

	respItem := appItemToResp(item)

	return ctx.JSON(http.StatusCreated, respItem)
}

// Get Item Info by Item ID
// (GET /items/{item_id})
func (h *HttpServer) GetItemsItemId(ctx echo.Context, itemId ItemId) error {
	item, err := h.itemService.GetItemByID(ctx.Request().Context(), string(itemId))
	if err != nil {
		return httpError(ctx, err)
	}

	respItem := appItemToResp(item)

	return ctx.JSON(http.StatusOK, respItem)
}

// Update Item
// (PATCH /items/{item_id})
func (h *HttpServer) PatchItemsItemid(ctx echo.Context, itemId ItemId) error {
	var itemPatch ItemPatch
	if err := ctx.Bind(&itemPatch); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "некорректные параметры"})
	}

	appItem := &app.Item{
		ID:       string(itemId),
		Name:     itemPatch.Name,
		Position: itemPatch.Position,
		Done:     itemPatch.Done,
	}

	item, err := h.itemService.Update(ctx.Request().Context(), appItem)
	if err != nil {
		return httpError(ctx, err)
	}

	respItem := appItemToResp(item)

	return ctx.JSON(http.StatusOK, respItem)
}

package ports

import (
	"strings"
	"time"

	"github.com/evgeniy-klemin/todo/internal/item/app"
	"github.com/pkg/errors"
)

func appItemsToRespItems(appItems []app.Item) []ItemResponse {
	var res []ItemResponse
	for _, appItem := range appItems {
		var respCreatedAt *time.Time
		if appItem.CreatedAt != nil {
			createdAt := (*appItem.CreatedAt).UTC()
			respCreatedAt = &createdAt
		}
		res = append(res, ItemResponse{
			Id:        appItem.ID,
			Name:      appItem.Name,
			Position:  appItem.Position,
			Done:      appItem.Done,
			CreatedAt: respCreatedAt,
		})
	}
	return res
}

func appItemToResp(appItem *app.Item) *ItemResponse {
	var respCreatedAt *time.Time
	if appItem.CreatedAt != nil {
		createdAt := (*appItem.CreatedAt).UTC()
		respCreatedAt = &createdAt
	}
	return &ItemResponse{
		Id:        appItem.ID,
		Name:      appItem.Name,
		Position:  appItem.Position,
		Done:      appItem.Done,
		CreatedAt: respCreatedAt,
	}
}

func getAppFieldsFromGetParam(fields *string) ([]app.ItemField, error) {
	var res []app.ItemField
	if fields != nil {
		strFields := strings.Split(*fields, ",")
		if len(strFields) > 0 {
			for _, strField := range strFields {
				var field app.ItemField
				switch strField {
				case "name":
					field = app.ItemFieldName
				case "position":
					field = app.ItemFieldPosition
				case "done":
					field = app.ItemFieldDone
				case "created_at":
					field = app.ItemFieldCreatedAt
				default:
					return nil, errors.Errorf("Field %s not found", strField)
				}
				res = append(res, field)
			}
		}
	}
	if len(res) == 0 {
		res = app.DefaultItemFields
	}
	return res, nil
}

func getSortFieldsFromGetParam(sort *string) (app.SortFields, error) {
	var sortFields app.SortFields
	if sort != nil {
		strFields := strings.Split(*sort, ",")
		if len(strFields) > 0 {
			for _, strField := range strFields {
				sortDirection := app.SortDirectionAsc
				if strings.HasPrefix(strField, "-") {
					sortDirection = app.SortDirectionDesc
					strField = strings.TrimLeft(strField, "-")
				}
				var field app.ItemField
				switch strField {
				case "name":
					field = app.ItemFieldName
				case "position":
					field = app.ItemFieldPosition
				case "done":
					field = app.ItemFieldDone
				case "created_at":
					field = app.ItemFieldCreatedAt
				default:
					return nil, errors.Errorf("Field %s not found", strField)
				}
				sortFields = append(sortFields, app.SortField{
					Field:         field,
					SortDirection: sortDirection,
				})
			}
		}
	}
	return sortFields, nil
}

package repository

import (
	"context"
	"database/sql"
	"errors"
	"fmt"
	"sync"

	"github.com/evgeniy-klemin/todo/internal/item/domain"
)

type Repository struct {
	db *sql.DB
	q  querier
	mu sync.Mutex
}

func NewSQLite(db *sql.DB, ftsEnabled bool) *Repository {
	return &Repository{
		db: db,
		q:  newSQLiteAdapter(db, ftsEnabled),
	}
}

func NewMySQL(db *sql.DB, ftsEnabled bool) *Repository {
	return &Repository{
		db: db,
		q:  newMySQLAdapter(db, ftsEnabled),
	}
}

func (r *Repository) maxPosition(ctx context.Context) (int, error) {
	result, err := r.q.MaxPosition(ctx)
	if err != nil {
		return 0, fmt.Errorf("max position query: %w", err)
	}
	return int(result), nil
}

func (r *Repository) AddWithNextPosition(ctx context.Context, item *domain.Item) (*domain.Item, error) {
	r.mu.Lock()
	defer r.mu.Unlock()

	max, err := r.maxPosition(ctx)
	if err != nil {
		return nil, fmt.Errorf("max position: %w", err)
	}

	if err := item.MoveTo(max + 1); err != nil {
		return nil, fmt.Errorf("move to position: %w", err)
	}

	return r.Add(ctx, item)
}

func (r *Repository) GetByID(ctx context.Context, id domain.ModelID) (*domain.Item, error) {
	item, err := r.q.GetItemByID(ctx, id.String())
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, domain.ErrNotFound
		}
		return nil, err
	}
	return toDomainItem(item)
}

func (r *Repository) getByID(ctx context.Context, tx *sql.Tx, id domain.ModelID) (*domain.Item, error) {
	txQ := r.q.WithTx(tx)
	item, err := txQ.GetItemByID(ctx, id.String())
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, domain.ErrNotFound
		}
		return nil, err
	}
	return toDomainItem(item)
}

// toDomainItem converts a dbItem to a domain.Item via ReconstituteItem.
func toDomainItem(item dbItem) (*domain.Item, error) {
	modelID, err := domain.NewModelID(item.ID)
	if err != nil {
		return nil, err
	}
	return domain.ReconstituteItem(modelID, item.Name, int(item.Position), item.Done, item.CreatedAt), nil
}

func (r *Repository) Add(ctx context.Context, item *domain.Item) (*domain.Item, error) {
	id := item.ID()
	err := r.q.InsertItem(
		ctx,
		id.String(),
		item.Name().String(),
		int64(item.Position().Int()),
		item.Done(),
		item.CreatedAt().UTC(),
	)
	if err != nil {
		return nil, fmt.Errorf("insert item: %w", err)
	}
	return item, nil
}

func (r *Repository) List(
	ctx context.Context,
	filter domain.ListFilter,
	sort []domain.SortField,
	page, perPage int,
) ([]*domain.Item, error) {
	dbSort := make([]sortField, len(sort))
	for i, s := range sort {
		dbSort[i] = sortField{Field: s.Field, Desc: s.Direction == domain.SortDesc}
	}

	dbRows, err := r.q.ListItems(ctx, listFilter{Done: filter.Done, Search: filter.Search}, dbSort, perPage, perPage*(page-1))
	if err != nil {
		return nil, fmt.Errorf("query items: %w", err)
	}

	res := make([]*domain.Item, 0, len(dbRows))
	for _, dbRow := range dbRows {
		domainItem, err := toDomainItem(dbRow)
		if err != nil {
			return nil, fmt.Errorf("convert item: %w", err)
		}
		res = append(res, domainItem)
	}
	return res, nil
}

func (r *Repository) Count(ctx context.Context, filter domain.ListFilter) (int, error) {
	count, err := r.q.CountItems(ctx, listFilter{Done: filter.Done, Search: filter.Search})
	if err != nil {
		return 0, fmt.Errorf("count items: %w", err)
	}
	return count, nil
}

func (r *Repository) Update(
	ctx context.Context,
	id domain.ModelID,
	updater func(item *domain.Item) error,
) (*domain.Item, error) {
	tx, err := r.db.BeginTx(ctx, nil)
	if err != nil {
		return nil, err
	}
	defer func() {
		_ = tx.Rollback()
	}()

	domainItem, err := r.getByID(ctx, tx, id)
	if err != nil {
		return nil, err
	}

	if err := updater(domainItem); err != nil {
		return nil, err
	}

	itemID := domainItem.ID()
	txQ := r.q.WithTx(tx)
	err = txQ.UpdateItem(
		ctx,
		domainItem.Name().String(),
		int64(domainItem.Position().Int()),
		domainItem.Done(),
		itemID.String(),
	)
	if err != nil {
		return nil, err
	}

	if err := tx.Commit(); err != nil {
		return nil, err
	}
	return domainItem, nil
}

package repository

import (
	"context"
	"database/sql"
	"strings"
	"time"
)

// dbItem is the internal transfer object between adapters and the repository.
type dbItem struct {
	ID        string
	Name      string
	Position  int64
	Done      bool
	CreatedAt time.Time
}

// listFilter carries the filter parameters for List/Count queries.
// It mirrors domain.ListFilter but avoids importing domain types into the adapter layer.
type listFilter struct {
	Done   *bool
	Search *string
}

// sortField carries a single ORDER BY field and direction.
type sortField struct {
	Field string
	Desc  bool
}

// buildOrderBy converts a slice of sortField into an ORDER BY clause string.
// Defaults to "position asc" when the slice is empty.
func buildOrderBy(sort []sortField) string {
	if len(sort) == 0 {
		return "position asc"
	}
	parts := make([]string, len(sort))
	for i, s := range sort {
		if s.Desc {
			parts[i] = s.Field + " desc"
		} else {
			parts[i] = s.Field + " asc"
		}
	}
	return strings.Join(parts, ", ")
}

// querier abstracts over the sqlc-generated query types for both SQLite and MySQL,
// allowing the repository to stay database-agnostic.
type querier interface {
	GetItemByID(ctx context.Context, id string) (dbItem, error)
	InsertItem(ctx context.Context, id, name string, position int64, done bool, createdAt time.Time) error
	UpdateItem(ctx context.Context, name string, position int64, done bool, id string) error
	MaxPosition(ctx context.Context) (int64, error)
	// ListItems executes a SELECT query applying filter, ORDER BY, LIMIT, OFFSET.
	ListItems(ctx context.Context, filter listFilter, sort []sortField, limit, offset int) ([]dbItem, error)
	// CountItems executes a COUNT query applying filter.
	CountItems(ctx context.Context, filter listFilter) (int, error)
	// WithTx returns a new querier backed by the given transaction.
	WithTx(tx *sql.Tx) querier
}

package repository

import (
	"context"
	"database/sql"
	"fmt"
	"strings"
	"time"

	"github.com/evgeniy-klemin/todo/internal/item/repository/sqlitedb"
)

type sqliteAdapter struct {
	q          *sqlitedb.Queries
	db         sqlitedb.DBTX
	ftsEnabled bool
}

func newSQLiteAdapter(db *sql.DB, ftsEnabled bool) *sqliteAdapter {
	return &sqliteAdapter{q: sqlitedb.New(db), db: db, ftsEnabled: ftsEnabled}
}

func (a *sqliteAdapter) GetItemByID(ctx context.Context, id string) (dbItem, error) {
	item, err := a.q.GetItemByID(ctx, id)
	if err != nil {
		return dbItem{}, err
	}
	return dbItem{
		ID:        item.ID,
		Name:      item.Name,
		Position:  item.Position,
		Done:      item.Done,
		CreatedAt: item.CreatedAt,
	}, nil
}

func (a *sqliteAdapter) InsertItem(ctx context.Context, id, name string, position int64, done bool, createdAt time.Time) error {
	return a.q.InsertItem(ctx, sqlitedb.InsertItemParams{
		ID:        id,
		Name:      name,
		Position:  position,
		Done:      done,
		CreatedAt: createdAt,
	})
}

func (a *sqliteAdapter) UpdateItem(ctx context.Context, name string, position int64, done bool, id string) error {
	return a.q.UpdateItem(ctx, sqlitedb.UpdateItemParams{
		Name:     name,
		Position: position,
		Done:     done,
		ID:       id,
	})
}

func (a *sqliteAdapter) MaxPosition(ctx context.Context) (int64, error) {
	return a.q.MaxPosition(ctx)
}

func (a *sqliteAdapter) WithTx(tx *sql.Tx) querier {
	return &sqliteAdapter{q: a.q.WithTx(tx), db: tx, ftsEnabled: a.ftsEnabled}
}

func (a *sqliteAdapter) ListItems(ctx context.Context, filter listFilter, sort []sortField, limit, offset int) ([]dbItem, error) {
	var conditions []string
	var args []any

	if filter.Done != nil {
		conditions = append(conditions, "done=?")
		args = append(args, *filter.Done)
	}
	if filter.Search != nil && *filter.Search != "" {
		cond, arg := a.searchCondition(*filter.Search)
		conditions = append(conditions, cond)
		args = append(args, arg)
	}

	q := "SELECT id, name, position, done, created_at FROM item"
	if len(conditions) > 0 {
		q += " WHERE " + strings.Join(conditions, " AND ")
	}
	q += " ORDER BY " + buildOrderBy(sort)
	q += " LIMIT ? OFFSET ?"
	queryArgs := make([]any, len(args), len(args)+2)
	copy(queryArgs, args)
	queryArgs = append(queryArgs, limit, offset)

	rows, err := a.db.QueryContext(ctx, q, queryArgs...)
	if err != nil {
		return nil, fmt.Errorf("list items: %w", err)
	}
	defer func() { _ = rows.Close() }()

	var result []dbItem
	for rows.Next() {
		var item dbItem
		if err := rows.Scan(&item.ID, &item.Name, &item.Position, &item.Done, &item.CreatedAt); err != nil {
			return nil, fmt.Errorf("list items: %w", err)
		}
		result = append(result, item)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("list items: %w", err)
	}
	return result, nil
}

func (a *sqliteAdapter) CountItems(ctx context.Context, filter listFilter) (int, error) {
	var conditions []string
	var args []any

	if filter.Done != nil {
		conditions = append(conditions, "done=?")
		args = append(args, *filter.Done)
	}
	if filter.Search != nil && *filter.Search != "" {
		cond, arg := a.searchCondition(*filter.Search)
		conditions = append(conditions, cond)
		args = append(args, arg)
	}

	q := "SELECT COUNT(*) FROM item"
	if len(conditions) > 0 {
		q += " WHERE " + strings.Join(conditions, " AND ")
	}
	var count int
	if err := a.db.QueryRowContext(ctx, q, args...).Scan(&count); err != nil {
		return 0, fmt.Errorf("count items: %w", err)
	}
	return count, nil
}

func (a *sqliteAdapter) searchCondition(search string) (string, any) {
	if a.ftsEnabled {
		return "item.rowid IN (SELECT rowid FROM item_fts WHERE item_fts MATCH ?)", buildFTSQuery(search)
	}
	return "LOWER(name) LIKE LOWER(?)", "%" + search + "%"
}

// buildFTSQuery converts a user search string into an FTS5 query with prefix matching.
// Example: "buy milk" -> "\"buy\"* \"milk\"*" (each word gets prefix matching)
func buildFTSQuery(search string) string {
	words := strings.Fields(search)
	for i, word := range words {
		word = strings.ReplaceAll(word, "\"", "\"\"")
		words[i] = "\"" + word + "\"" + "*"
	}
	return strings.Join(words, " ")
}

